import{_ as i,o as a,c as e,a9 as r}from"./chunks/framework.STMWz9Nm.js";const c=JSON.parse('{"title":"负载均衡与容错机制","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/13-Dubbo学习/03-负载均衡与容错机制.md","filePath":"语言/java/13-Dubbo学习/03-负载均衡与容错机制.md","lastUpdated":1777177198000}'),h={name:"语言/java/13-Dubbo学习/03-负载均衡与容错机制.md"};function s(n,l,t,o,p,d){return a(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="负载均衡与容错机制" tabindex="-1">负载均衡与容错机制 <a class="header-anchor" href="#负载均衡与容错机制" aria-label="Permalink to “负载均衡与容错机制”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>很多人刚学 Dubbo 时，会把“负载均衡”和“容错”混成一件事。</p><p>其实它们解决的是两个不同层面的问题：</p><ul><li><strong>负载均衡</strong>：这次请求应该打到哪个 Provider</li><li><strong>容错机制</strong>：如果这次调用失败了，接下来怎么办</li></ul><p>你可以先这样理解：</p><blockquote><p><strong>负载均衡决定“选谁来处理”，容错机制决定“处理失败后怎么办”。</strong></p></blockquote><p>比如现在有 3 台用户服务：</p><ul><li>10.0.0.11</li><li>10.0.0.12</li><li>10.0.0.13</li></ul><p>Consumer 发起一次请求时，首先要回答：</p><ul><li>这次选哪一台？</li></ul><p>这就是负载均衡。</p><p>如果刚好选中的那台超时了，还要继续回答：</p><ul><li>是直接报错？</li><li>还是换一台重试？</li><li>还是快速失败？</li><li>还是返回默认值？</li></ul><p>这就是容错机制。</p><hr><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>远程调用和本地方法调用最大的区别之一是：</p><ul><li>本地调用失败的变量少</li><li>远程调用失败的变量很多</li></ul><p>例如：</p><ul><li>某台机器负载飙高</li><li>网络抖动</li><li>服务实例重启</li><li>单个节点 GC 卡顿</li><li>某个机房延迟变大</li></ul><p>如果没有合理的负载均衡和容错策略，就会出现：</p><ul><li>流量总压到少数节点</li><li>故障节点持续被打爆</li><li>一次超时引发级联重试</li><li>写请求被重复执行</li><li>整条链路被拖慢</li></ul><p>所以这一章的本质，不只是讲几个策略名词，而是在回答：</p><blockquote><p><strong>分布式系统里，怎么把“偶发失败”控制在可接受范围内。</strong></p></blockquote><hr><h2 id="_3-先建立最核心的直觉" tabindex="-1">3. 先建立最核心的直觉 <a class="header-anchor" href="#_3-先建立最核心的直觉" aria-label="Permalink to “3. 先建立最核心的直觉”">​</a></h2><p>可以把 Dubbo 调用看成“打车”：</p><h3 id="负载均衡像什么" tabindex="-1">负载均衡像什么 <a class="header-anchor" href="#负载均衡像什么" aria-label="Permalink to “负载均衡像什么”">​</a></h3><p>像你在平台上打车，系统要从附近司机里挑一个：</p><ul><li>随机挑</li><li>轮流分配</li><li>优先给距离近的</li><li>尽量让同一个乘客总是分到同一类司机</li></ul><h3 id="容错像什么" tabindex="-1">容错像什么 <a class="header-anchor" href="#容错像什么" aria-label="Permalink to “容错像什么”">​</a></h3><p>像你叫的车如果取消了，你要怎么处理：</p><ul><li>重新叫一辆</li><li>立刻放弃</li><li>换别的平台</li><li>返回一个兜底方案</li></ul><p>所以你会发现：</p><ul><li><strong>负载均衡发生在“调用前”</strong></li><li><strong>容错策略发生在“调用失败后”</strong></li></ul><p>这两个动作顺序不同，作用也不同。</p><hr><h2 id="_4-常见负载均衡策略" tabindex="-1">4. 常见负载均衡策略 <a class="header-anchor" href="#_4-常见负载均衡策略" aria-label="Permalink to “4. 常见负载均衡策略”">​</a></h2><h2 id="_4-1-random-随机" tabindex="-1">4.1 Random：随机 <a class="header-anchor" href="#_4-1-random-随机" aria-label="Permalink to “4.1 Random：随机”">​</a></h2><p>随机是最常见、也最容易理解的一种。</p><p>特点：</p><ul><li>从多个 Provider 中随机选一个</li><li>实现简单</li><li>在实例数量足够多、请求量足够大时，整体分布通常比较均匀</li></ul><p>适合：</p><ul><li>大多数普通读请求</li><li>节点性能比较接近的场景</li></ul><p>通俗理解：</p><ul><li>每次从可用实例里随机抽一个</li></ul><h3 id="优点" tabindex="-1">优点 <a class="header-anchor" href="#优点" aria-label="Permalink to “优点”">​</a></h3><ul><li>简单</li><li>分布通常比较自然</li><li>不容易因为顺序固定导致局部热点</li></ul><h3 id="缺点" tabindex="-1">缺点 <a class="header-anchor" href="#缺点" aria-label="Permalink to “缺点”">​</a></h3><ul><li>单次短时间窗口内可能不均匀</li><li>不考虑实例当前真实负载</li></ul><hr><h2 id="_4-2-round-robin-轮询" tabindex="-1">4.2 Round Robin：轮询 <a class="header-anchor" href="#_4-2-round-robin-轮询" aria-label="Permalink to “4.2 Round Robin：轮询”">​</a></h2><p>轮询的思路是：</p><ul><li>这次给 A</li><li>下次给 B</li><li>再下次给 C</li><li>然后再回到 A</li></ul><p>适合：</p><ul><li>节点性能相近</li><li>请求耗时也比较接近</li></ul><h3 id="优点-1" tabindex="-1">优点 <a class="header-anchor" href="#优点-1" aria-label="Permalink to “优点”">​</a></h3><ul><li>直观</li><li>理论上分配比较平均</li></ul><h3 id="缺点-1" tabindex="-1">缺点 <a class="header-anchor" href="#缺点-1" aria-label="Permalink to “缺点”">​</a></h3><p>如果某一台机器虽然“轮到它了”，但它刚好很慢，轮询并不会自动避开它。</p><p>所以轮询的问题在于：</p><ul><li>它只关注“分配顺序”</li><li>不关注“实例当前状态”</li></ul><hr><h2 id="_4-3-least-active-最少活跃调用数" tabindex="-1">4.3 Least Active：最少活跃调用数 <a class="header-anchor" href="#_4-3-least-active-最少活跃调用数" aria-label="Permalink to “4.3 Least Active：最少活跃调用数”">​</a></h2><p>这个策略更关注当前实例是否忙。</p><p>它会优先选择：</p><ul><li>当前正在处理请求数更少的实例</li></ul><p>通俗理解：</p><ul><li>谁现在手头活少，就先把新请求给谁</li></ul><p>适合：</p><ul><li>各实例处理能力不同</li><li>请求耗时差异较大</li></ul><h3 id="优点-2" tabindex="-1">优点 <a class="header-anchor" href="#优点-2" aria-label="Permalink to “优点”">​</a></h3><ul><li>比纯随机、纯轮询更能反映当前负载情况</li></ul><h3 id="缺点-2" tabindex="-1">缺点 <a class="header-anchor" href="#缺点-2" aria-label="Permalink to “缺点”">​</a></h3><ul><li>实现和理解都稍复杂</li><li>对统计数据准确性有依赖</li></ul><hr><h2 id="_4-4-consistent-hash-一致性哈希" tabindex="-1">4.4 Consistent Hash：一致性哈希 <a class="header-anchor" href="#_4-4-consistent-hash-一致性哈希" aria-label="Permalink to “4.4 Consistent Hash：一致性哈希”">​</a></h2><p>一致性哈希常见于“同一类请求尽量打到同一台机器”的场景。</p><p>例如：</p><ul><li>同一个用户 ID 的请求尽量落到同一实例</li><li>同一个会话尽量命中同一机器上的缓存</li></ul><p>通俗理解：</p><ul><li>不是随机选机器</li><li>而是根据某个 key 算出“它更适合去哪台机器”</li></ul><p>适合：</p><ul><li>有会话粘性需求</li><li>希望同类请求稳定命中同一节点</li><li>本地缓存命中率很重要</li></ul><h3 id="优点-3" tabindex="-1">优点 <a class="header-anchor" href="#优点-3" aria-label="Permalink to “优点”">​</a></h3><ul><li>同一个 key 通常映射到固定实例</li><li>有利于局部缓存命中</li></ul><h3 id="缺点-3" tabindex="-1">缺点 <a class="header-anchor" href="#缺点-3" aria-label="Permalink to “缺点”">​</a></h3><ul><li>节点变更时，映射关系会变化</li><li>不适合所有业务都无脑使用</li></ul><hr><h2 id="_5-负载均衡到底怎么选" tabindex="-1">5. 负载均衡到底怎么选 <a class="header-anchor" href="#_5-负载均衡到底怎么选" aria-label="Permalink to “5. 负载均衡到底怎么选”">​</a></h2><p>没有“永远最好的”策略，只有“更适合当前业务”的策略。</p><p>可以先这么记：</p><ul><li><strong>普通均匀流量</strong>：随机很常见</li><li><strong>追求平均分配</strong>：轮询可作为入门理解</li><li><strong>实例忙闲差异明显</strong>：最少活跃更合适</li><li><strong>希望同一类请求稳定落同一机器</strong>：一致性哈希更合适</li></ul><p>不要把负载均衡理解成一道标准答案题，它更像权衡题。</p><hr><h2 id="_6-常见容错策略" tabindex="-1">6. 常见容错策略 <a class="header-anchor" href="#_6-常见容错策略" aria-label="Permalink to “6. 常见容错策略”">​</a></h2><p>容错机制解决的是：</p><ul><li>调用失败后怎么处理</li></ul><p>这件事一定要结合业务类型来定。</p><h2 id="_6-1-failfast-快速失败" tabindex="-1">6.1 Failfast：快速失败 <a class="header-anchor" href="#_6-1-failfast-快速失败" aria-label="Permalink to “6.1 Failfast：快速失败”">​</a></h2><p>含义是：</p><ul><li>调用失败后立刻报错</li><li>不做额外重试</li></ul><p>适合：</p><ul><li>非幂等写请求</li><li>对重复执行敏感的操作</li></ul><p>例如：</p><ul><li>扣库存</li><li>下单</li><li>支付确认</li></ul><p>为什么适合写请求？</p><p>因为很多写操作不能随便重试，不然可能产生重复副作用。</p><hr><h2 id="_6-2-failover-失败转移" tabindex="-1">6.2 Failover：失败转移 <a class="header-anchor" href="#_6-2-failover-失败转移" aria-label="Permalink to “6.2 Failover：失败转移”">​</a></h2><p>含义是：</p><ul><li>调用某个 Provider 失败后</li><li>再换一个 Provider 继续重试</li></ul><p>适合：</p><ul><li>幂等读请求</li><li>查询类请求</li></ul><p>例如：</p><ul><li>查用户资料</li><li>查商品详情</li><li>查配置</li></ul><h3 id="优点-4" tabindex="-1">优点 <a class="header-anchor" href="#优点-4" aria-label="Permalink to “优点”">​</a></h3><ul><li>能提高读请求成功率</li></ul><h3 id="风险" tabindex="-1">风险 <a class="header-anchor" href="#风险" aria-label="Permalink to “风险”">​</a></h3><ul><li>会放大调用次数</li><li>在下游整体不稳定时，可能让雪崩更严重</li></ul><p>所以要特别注意：</p><blockquote><p><strong>重试不是免费补救，它会扩大流量。</strong></p></blockquote><hr><h2 id="_6-3-failsafe-失败安全" tabindex="-1">6.3 Failsafe：失败安全 <a class="header-anchor" href="#_6-3-failsafe-失败安全" aria-label="Permalink to “6.3 Failsafe：失败安全”">​</a></h2><p>含义通常是：</p><ul><li>调用失败后，不抛出强错误</li><li>记录日志或忽略异常</li></ul><p>适合：</p><ul><li>非核心辅助操作</li><li>不影响主流程的统计、审计类动作</li></ul><p>例如：</p><ul><li>异步埋点</li><li>非关键日志上报</li></ul><p>不适合：</p><ul><li>核心交易流程</li></ul><hr><h2 id="_6-4-failback-失败自动恢复" tabindex="-1">6.4 Failback：失败自动恢复 <a class="header-anchor" href="#_6-4-failback-失败自动恢复" aria-label="Permalink to “6.4 Failback：失败自动恢复”">​</a></h2><p>含义是：</p><ul><li>失败后先记录下来</li><li>后续再后台重试补偿</li></ul><p>适合：</p><ul><li>允许最终一致</li><li>不要求请求必须同步成功</li></ul><p>例如：</p><ul><li>某些通知、消息补偿类场景</li></ul><hr><h2 id="_6-5-forking-broadcast-了解即可" tabindex="-1">6.5 Forking / Broadcast（了解即可） <a class="header-anchor" href="#_6-5-forking-broadcast-了解即可" aria-label="Permalink to “6.5 Forking / Broadcast（了解即可）”">​</a></h2><p>有些策略会：</p><ul><li>并行调用多个实例，谁先返回用谁</li><li>或广播到所有实例</li></ul><p>这些策略适用面更窄，通常只在特定场景下使用。</p><p>入门阶段先重点掌握：</p><ul><li>快速失败</li><li>失败转移</li></ul><p>就够用了。</p><hr><h2 id="_7-为什么写请求通常不适合盲目重试" tabindex="-1">7. 为什么写请求通常不适合盲目重试 <a class="header-anchor" href="#_7-为什么写请求通常不适合盲目重试" aria-label="Permalink to “7. 为什么写请求通常不适合盲目重试”">​</a></h2><p>这是实战里最重要的点之一。</p><p>假设你有一个创建订单接口：</p><div class="language-java"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">createOrder</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(userId, productId)</span></span></code></pre></div><p>如果第一次调用已经在服务端执行成功，但 Consumer 因为网络超时没收到结果，这时如果再重试一次，可能发生：</p><ul><li>第二次又创建出一个订单</li><li>或第二次扣减了一次库存</li></ul><p>于是就出现了典型问题：</p><ul><li>重复下单</li><li>重复扣款</li><li>重复发券</li></ul><p>所以写请求一般要谨慎：</p><ul><li>能不重试就别乱重试</li><li>真要重试，必须有幂等保障</li></ul><p>这也是为什么：</p><blockquote><p><strong>读请求和写请求的容错策略，往往不能一刀切。</strong></p></blockquote><hr><h2 id="_8-动手验证-感受策略差异" tabindex="-1">8. 动手验证：感受策略差异 <a class="header-anchor" href="#_8-动手验证-感受策略差异" aria-label="Permalink to “8. 动手验证：感受策略差异”">​</a></h2><p>如果你本地有 Dubbo 环境，可以做几个小实验。</p><h3 id="_8-1-准备两个-provider" tabindex="-1">8.1 准备两个 Provider <a class="header-anchor" href="#_8-1-准备两个-provider" aria-label="Permalink to “8.1 准备两个 Provider”">​</a></h3><p>例如启动两个用户服务实例：</p><ul><li>provider-A</li><li>provider-B</li></ul><h3 id="_8-2-故意让一个实例变慢" tabindex="-1">8.2 故意让一个实例变慢 <a class="header-anchor" href="#_8-2-故意让一个实例变慢" aria-label="Permalink to “8.2 故意让一个实例变慢”">​</a></h3><p>在其中一个实例里加：</p><div class="language-java"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Thread.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sleep</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><h3 id="_8-3-连续发起请求" tabindex="-1">8.3 连续发起请求 <a class="header-anchor" href="#_8-3-连续发起请求" aria-label="Permalink to “8.3 连续发起请求”">​</a></h3><p>观察：</p><ul><li>随机策略下，请求分布是否均匀</li><li>轮询策略下，是否会稳定轮到慢实例</li><li>最少活跃策略下，慢实例是否逐渐少接请求</li></ul><h3 id="_8-4-再模拟失败" tabindex="-1">8.4 再模拟失败 <a class="header-anchor" href="#_8-4-再模拟失败" aria-label="Permalink to “8.4 再模拟失败”">​</a></h3><p>把其中一个实例停掉，观察：</p><ul><li>快速失败时，Consumer 如何报错</li><li>失败转移时，是否会切到另一台实例继续调用</li></ul><p>这类实验能让你真正理解：</p><ul><li>负载均衡在选谁</li><li>容错策略在失败后怎么收场</li></ul><hr><h2 id="_9-超时设置为什么和容错强相关" tabindex="-1">9. 超时设置为什么和容错强相关 <a class="header-anchor" href="#_9-超时设置为什么和容错强相关" aria-label="Permalink to “9. 超时设置为什么和容错强相关”">​</a></h2><p>很多人只盯着“重试次数”，却忽略超时。</p><p>其实超时是容错里的关键参数。</p><p>比如：</p><ul><li>单次超时 5 秒</li><li>重试 2 次</li></ul><p>那一次最坏调用时间，可能就远超你想象。</p><p>这会导致：</p><ul><li>上游线程堆积</li><li>接口整体变慢</li><li>故障在链路里层层放大</li></ul><p>所以容错不是只看“要不要重试”，还要同时看：</p><ul><li>超时多久</li><li>重试几次</li><li>总体 SLA 能否接受</li></ul><hr><h2 id="_10-最容易踩的坑" tabindex="-1">10. 最容易踩的坑 <a class="header-anchor" href="#_10-最容易踩的坑" aria-label="Permalink to “10. 最容易踩的坑”">​</a></h2><h3 id="_10-1-所有接口统一重试" tabindex="-1">10.1 所有接口统一重试 <a class="header-anchor" href="#_10-1-所有接口统一重试" aria-label="Permalink to “10.1 所有接口统一重试”">​</a></h3><p>这是最危险的做法之一。</p><p>读写不分地统一重试，极容易把写接口搞出重复副作用。</p><h3 id="_10-2-看到失败就拼命重试" tabindex="-1">10.2 看到失败就拼命重试 <a class="header-anchor" href="#_10-2-看到失败就拼命重试" aria-label="Permalink to “10.2 看到失败就拼命重试”">​</a></h3><p>当下游已经不稳定时，盲目重试往往不是修复，而是放大故障。</p><h3 id="_10-3-只关注平均分配-不关注实例健康" tabindex="-1">10.3 只关注平均分配，不关注实例健康 <a class="header-anchor" href="#_10-3-只关注平均分配-不关注实例健康" aria-label="Permalink to “10.3 只关注平均分配，不关注实例健康”">​</a></h3><p>负载均衡不是“分得平均”就够了，还要关注：</p><ul><li>某台实例是不是已经慢了</li><li>某台实例是不是故障前兆</li></ul><h3 id="_10-4-一致性哈希乱用" tabindex="-1">10.4 一致性哈希乱用 <a class="header-anchor" href="#_10-4-一致性哈希乱用" aria-label="Permalink to “10.4 一致性哈希乱用”">​</a></h3><p>如果业务根本不需要“同类请求稳定命中同一实例”，那上来就用一致性哈希，只会增加理解和维护成本。</p><h3 id="_10-5-超时设置过大" tabindex="-1">10.5 超时设置过大 <a class="header-anchor" href="#_10-5-超时设置过大" aria-label="Permalink to “10.5 超时设置过大”">​</a></h3><p>超时过大会导致故障暴露太慢，线程和连接资源会被拖住。</p><hr><h2 id="_11-一套实用决策思路" tabindex="-1">11. 一套实用决策思路 <a class="header-anchor" href="#_11-一套实用决策思路" aria-label="Permalink to “11. 一套实用决策思路”">​</a></h2><p>以后你给某个 Dubbo 接口选策略时，可以先问自己 4 个问题：</p><ol><li>这是读请求还是写请求？</li><li>它是不是幂等？</li><li>调用失败后，业务是更怕“失败”，还是更怕“重复执行”？</li><li>下游实例之间是否需要稳定路由到同一台？</li></ol><p>通常可以得到一个比较务实的起点：</p><ul><li><strong>查询类接口</strong>：可考虑失败转移 + 合理超时</li><li><strong>核心写接口</strong>：优先快速失败 + 业务幂等设计</li><li><strong>本地缓存敏感接口</strong>：可评估一致性哈希</li></ul><hr><h2 id="_12-练习建议" tabindex="-1">12. 练习建议 <a class="header-anchor" href="#_12-练习建议" aria-label="Permalink to “12. 练习建议”">​</a></h2><h3 id="练习-1-为读写接口分别选策略" tabindex="-1">练习 1：为读写接口分别选策略 <a class="header-anchor" href="#练习-1-为读写接口分别选策略" aria-label="Permalink to “练习 1：为读写接口分别选策略”">​</a></h3><p>任选两个接口：</p><ul><li>一个查询接口</li><li>一个写入接口</li></ul><p>分别设计：</p><ul><li>负载均衡方式</li><li>容错策略</li><li>超时设置</li></ul><h3 id="练习-2-模拟一次下游故障" tabindex="-1">练习 2：模拟一次下游故障 <a class="header-anchor" href="#练习-2-模拟一次下游故障" aria-label="Permalink to “练习 2：模拟一次下游故障”">​</a></h3><p>步骤：</p><ol><li>启动两个 Provider</li><li>停掉其中一个</li><li>观察不同容错策略的行为差异</li></ol><h3 id="练习-3-思考重试风险" tabindex="-1">练习 3：思考重试风险 <a class="header-anchor" href="#练习-3-思考重试风险" aria-label="Permalink to “练习 3：思考重试风险”">​</a></h3><p>找一个“创建/扣减/支付”类接口，分析：</p><ul><li>如果 Consumer 因超时重试，会造成什么副作用</li></ul><hr><h2 id="_13-自测问题" tabindex="-1">13. 自测问题 <a class="header-anchor" href="#_13-自测问题" aria-label="Permalink to “13. 自测问题”">​</a></h2><ul><li>负载均衡和容错分别解决什么问题？</li><li>为什么写请求通常不适合盲目重试？</li><li>一致性哈希最适合哪类场景？</li><li>超时设置为什么会直接影响容错效果？</li><li>当下游已经抖动时，为什么重试可能会放大故障？</li></ul><hr><h2 id="_14-这一章你至少要带走什么" tabindex="-1">14. 这一章你至少要带走什么 <a class="header-anchor" href="#_14-这一章你至少要带走什么" aria-label="Permalink to “14. 这一章你至少要带走什么”">​</a></h2><p>如果你看完只记住 4 件事，就先记这 4 件：</p><ol><li><strong>负载均衡负责选实例，容错机制负责处理失败</strong></li><li><strong>读请求和写请求不能用同一套重试思路</strong></li><li><strong>重试会放大流量，必须谨慎设置</strong></li><li><strong>超时、负载策略、容错策略要一起看，不能孤立配置</strong></li></ol><p>把这几个点建立起来，后面你看 Dubbo 的集群容错配置时，就不会只停留在“背策略名”了。</p>',231)])])}const b=i(h,[["render",s]]);export{c as __pageData,b as default};
